				input.workItemId,
				claimToken,
				"pending",
				input.workItemTitle,
				input.workItemUrl ?? null,
				input.workItemStatus ?? null,
				workItemSnapshotJson,
				now,
				now,
			],
		});

		await tx.execute({
			sql: `
				INSERT INTO attempts (
					id,
					run_id,
					attempt_number,
					status,
					created_at,
					updated_at
				)
				VALUES (?, ?, ?, ?, ?, ?)
			`,
			args: [attemptId, runId, 1, "pending", now, now],
		});

		await tx.execute({
			sql: `
				INSERT INTO events (
					id,
					run_id,
					attempt_id,
					level,
					type,
					message,
					data_json,
					created_at
				)
				VALUES (?, ?, ?, ?, ?, ?, ?, ?)
			`,
			args: [
				eventId,
				runId,
				attemptId,
				"info",
				"manual_run.created",
				"Manual run created.",
				JSON.stringify({ workItemId: input.workItemId, claimedBy: input.claimedBy }),
				now,
			],
		});

		await tx.commit();

		return {
			acquired: true,
			claimToken,
			claimExpiresAt,
			runId,
			attemptId,
			eventId,
			createdAt: now,
		};
	} catch (error) {
		await tx.rollback();
		throw error;
	} finally {
		tx.close();
	}
}

export async function createManualRun(
	client: Client,
	input: CreateManualRunInput,
): Promise<CreatedRun> {
	const now = input.now ?? Date.now();
	const id = input.id ?? createPrefixedId("run");
	const status = input.status ?? "pending";

	await client.execute({
		sql: `
			INSERT INTO runs (
				id,
				work_item_id,
				claim_token,
				status,
				work_item_title,
				work_item_url,
				work_item_status,
				work_item_snapshot_json,
				created_at,
				updated_at
			)
			VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		`,
		args: [
			id,
			input.workItemId,
			input.claimToken,
			status,
			input.workItemTitle,
			input.workItemUrl ?? null,
			input.workItemStatus ?? null,
			JSON.stringify(input.workItemSnapshot ?? {}),
			now,
			now,
		],
	});

	return { id, status, createdAt: now };
}

export async function createAttempt(
	client: Client,
	input: CreateAttemptInput,
): Promise<CreatedAttempt> {
	const now = input.now ?? Date.now();
	const id = input.id ?? createPrefixedId("att");
	const status = input.status ?? "pending";

	await client.execute({
		sql: `
			INSERT INTO attempts (
				id,
				run_id,
				attempt_number,
				status,
				sandbox_id,
				command,
				created_at,
				updated_at
			)
			VALUES (?, ?, ?, ?, ?, ?, ?, ?)
		`,
		args: [
			id,
			input.runId,
			input.attemptNumber,
			status,
			input.sandboxId ?? null,
			input.command ?? null,
			now,
			now,
		],
	});

	return { id, status, createdAt: now };
}

export async function createEvent(
	client: Client,
	input: CreateEventInput,
): Promise<CreatedEvent> {
	const now = input.now ?? Date.now();
	const id = input.id ?? createPrefixedId("evt");
	const level = input.level ?? "info";

	await client.execute({
		sql: `
			INSERT INTO events (
				id,
				run_id,
				attempt_id,
				level,
				type,
				message,
				data_json,
				created_at
			)
			VALUES (?, ?, ?, ?, ?, ?, ?, ?)
		`,
		args: [
			id,
			input.runId ?? null,
			input.attemptId ?? null,
			level,
			input.type,
			input.message ?? null,
			input.data === undefined ? null : JSON.stringify(input.data),
			now,
		],
	});

